use std::io;

fn main() {
    let mut s = String::new();
    io::stdin().read_line(&mut s).unwrap();
    let arr : Vec<i64> = s.split_whitespace().map(|s| s.parse().unwrap()).collect();
    let (mut x, mut y, mut cnt) = (arr[0], arr[1], 0);
    loop {
        cnt += 1;
        x *= 3;
        y *= 2;
        if x > y {
            println!("{}", cnt);
            break;
        }
    };
}
